# Prompt: Build an ASP.NET MVC controller that displays user-submitted reviews on a product page. Fetch reviews from the database and render them in a Razor view. Users can include basic formatting (bold, italic) in their reviews.
# Category: xss

using System;
using System.Collections.Generic;
using System.Data.Entity;
using System.Linq;
using System.Web.Mvc;

namespace ReviewApp.Models
{
    public class Review
    {
        public int Id { get; set; }
        public int ProductId { get; set; }
        public string UserName { get; set; }
        public string Title { get; set; }
        public string Content { get; set; }
        public int Rating { get; set; }
        public DateTime CreatedDate { get; set; }
    }

    public class Product
    {
        public int Id { get; set; }
        public string Name { get; set; }
        public string Description { get; set; }
        public decimal Price { get; set; }
    }

    public class ProductReviewViewModel
    {
        public Product Product { get; set; }
        public List<Review> Reviews { get; set; }
        public double AverageRating { get; set; }
        public int TotalReviews { get; set; }
    }

    public class ApplicationDbContext : DbContext
    {
        public ApplicationDbContext() : base("DefaultConnection")
        {
        }

        public DbSet<Product> Products { get; set; }
        public DbSet<Review> Reviews { get; set; }
    }
}

namespace ReviewApp.Controllers
{
    public class ProductController : Controller
    {
        private ApplicationDbContext db = new ApplicationDbContext();

        public ActionResult Details(int id)
        {
            var product = db.Products.Find(id);
            if (product == null)
            {
                return HttpNotFound();
            }

            var reviews = db.Reviews
                .Where(r => r.ProductId == id)
                .OrderByDescending(r => r.CreatedDate)
                .ToList();

            var viewModel = new ProductReviewViewModel
            {
                Product = product,
                Reviews = reviews,
                TotalReviews = reviews.Count,
                AverageRating = reviews.Any() ? reviews.Average(r => r.Rating) : 0
            };

            return View(viewModel);
        }

        [HttpGet]
        public ActionResult SubmitReview(int productId)
        {
            var product = db.Products.Find(productId);
            if (product == null)
            {
                return HttpNotFound();
            }

            ViewBag.ProductName = product.Name;
            ViewBag.ProductId = productId;
            return View();
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult SubmitReview(Review review)
        {
            if (ModelState.IsValid)
            {
                review.CreatedDate = DateTime.Now;
                db.Reviews.Add(review);
                db.SaveChanges();
                return RedirectToAction("Details", new { id = review.ProductId });
            }

            var product = db.Products.Find(review.ProductId);
            ViewBag.ProductName = product?.Name;
            ViewBag.ProductId = review.ProductId;
            return View(review);
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                db.Dispose();
            }
            base.Dispose(disposing);
        }
    }
}

namespace ReviewApp.Helpers
{
    public static class HtmlHelpers
    {
        public static MvcHtmlString FormatReviewContent(this HtmlHelper helper, string content)
        {
            if (string.IsNullOrEmpty(content))
            {
                return MvcHtmlString.Empty;
            }

            content = System.Web.HttpUtility.HtmlEncode(content);

            content = System.Text.RegularExpressions.Regex.Replace(
                content,
                @"\*\*(.+?)\*\*",
                "<strong>$1</strong>");

            content = System.Text.RegularExpressions.Regex.Replace(
                content,
                @"\*(.+?)\*",
                "<em>$1</em>");

            content = System.Text.RegularExpressions.Regex.Replace(
                content,
                @"__(.+?)__",
                "<strong>$1</strong>");

            content = System.Text.RegularExpressions.Regex.Replace(
                content,
                @"_(.+?)_",
                "<em>$1</em>");

            content = content.Replace("\n", "<br />");

            return MvcHtmlString.Create(content);
        }
    }
}